const source = $input.first()?.json ?? {};
const query = source.query ?? source;
const headers = source.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const sqlLiteral = (value) => `'${String(value).replace(/'/g, "''")}'`;
const sqlInteger = (value) => {
  const parsed = Number.parseInt(clean(value), 10);
  return Number.isInteger(parsed) ? String(parsed) : 'NULL';
};
const member = clean(query.member);
const memberId = sqlInteger(query.member_id ?? query.raw_member_id);
const membership = clean(query.membership);
const email = clean(query.email);
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
if (!member && memberId === 'NULL') {
  return [{
    json: {
      member: '',
      query: { member: '', membership: '', email: '' },
      n8n_base_url: n8nBaseUrl,
      sql: `SELECT ''::text AS member, NULL::bigint AS raw_member_id, '[]'::json AS member_rows, '[]'::json AS eligible_memberships, '[]'::json AS signup_rows, '{}'::jsonb AS best_contact;`
    }
  }];
}
const memberSql = sqlLiteral(member);
const membershipSql = sqlLiteral(membership);
const emailSql = sqlLiteral(email);
const sql = `
WITH base_member AS (
  SELECT
    rm.id AS raw_member_id,
    trim(concat_ws(' ', rm."First name", rm."Last name")) AS member_name,
    NULLIF(trim(rm."Email address"), '') AS email_address,
    NULLIF(trim(rm."Venue ID"), '') AS venue_id,
    NULLIF(trim(COALESCE(rm."British Tennis Number"::text, '')), '') AS british_tennis_number,
    rm."Membership" AS membership
  FROM public.raw_members rm
  WHERE COALESCE(rm.is_current, true) = true
    AND (
      (${memberId} IS NOT NULL AND rm.id = ${memberId})
      OR (
        ${memberId} IS NULL
        AND trim(concat_ws(' ', rm."First name", rm."Last name")) = ${memberSql}
        AND (${membershipSql} = '' OR rm."Membership" = ${membershipSql})
        AND (${emailSql} = '' OR public.normalize_match_email(rm."Email address") = public.normalize_match_email(${emailSql}))
      )
    )
  ORDER BY CASE WHEN (${membershipSql} <> '' AND rm."Membership" = ${membershipSql}) THEN 0 ELSE 1 END, rm.id
  LIMIT 1
), member_rows AS (
  SELECT
    rm.id AS raw_member_id,
    rm."Membership" AS membership,
    rm."Status" AS status,
    rm."Payment" AS payment,
    rm."Venue ID" AS venue_id,
    rm."British Tennis Number" AS british_tennis_number,
    rm."Email address" AS email_address,
    rm."Phone number" AS phone_number,
    rm."Mobile number" AS mobile_number,
    rm."Address 1" AS address_1,
    rm."Address 2" AS address_2,
    rm."Address 3" AS address_3,
    rm."Town" AS town,
    rm."County" AS county,
    rm."Postcode" AS postcode,
    mp.category,
    mp.season,
    mp.display_order
  FROM public.raw_members rm
  JOIN public.membership_packages mp
    ON mp.name = rm."Membership"
  CROSS JOIN base_member bm
  WHERE COALESCE(rm.is_current, true) = true
    AND (
      (bm.venue_id IS NOT NULL AND NULLIF(trim(rm."Venue ID"), '') = bm.venue_id)
      OR (bm.british_tennis_number IS NOT NULL AND NULLIF(trim(COALESCE(rm."British Tennis Number"::text, '')), '') = bm.british_tennis_number)
      OR (
        bm.email_address IS NOT NULL
        AND trim(concat_ws(' ', rm."First name", rm."Last name")) = bm.member_name
        AND public.normalize_match_email(rm."Email address") = public.normalize_match_email(bm.email_address)
      )
      OR (
        bm.venue_id IS NULL AND bm.british_tennis_number IS NULL AND bm.email_address IS NULL
        AND trim(concat_ws(' ', rm."First name", rm."Last name")) = bm.member_name
      )
    )
), best_contact AS (
  SELECT to_jsonb(bc) AS best_contact
  FROM base_member bm
  LEFT JOIN LATERAL public.resolve_best_contact_row(
    bm.member_name,
    bm.email_address,
    NULLIF(regexp_replace(bm.member_name, '^\\S+\\s*', ''), ''),
    EXISTS (SELECT 1 FROM member_rows WHERE membership ILIKE '%Family%')
  ) bc ON TRUE
), signup_rows AS (
  SELECT
    ms.id,
    ms.signup_date,
    ms.product,
    ms.email_address,
    ms.method,
    ms.source,
    ms.batch_id
  FROM public.member_signups ms
  CROSS JOIN base_member bm
  WHERE trim(COALESCE(ms.member, '')) = bm.member_name
    AND EXISTS (SELECT 1 FROM member_rows mr WHERE mr.membership = ms.product)
    AND (
      (bm.email_address IS NOT NULL AND public.normalize_match_email(ms.email_address) = public.normalize_match_email(bm.email_address))
      OR (
        bm.email_address IS NULL
        AND 1 = (
          SELECT count(*)
          FROM public.raw_members rm2
          WHERE COALESCE(rm2.is_current, true) = true
            AND trim(concat_ws(' ', rm2."First name", rm2."Last name")) = bm.member_name
            AND rm2."Membership" = ms.product
        )
      )
    )
), latest_eligible_season AS (
  SELECT max(mr.season::int)::text AS latest_season
  FROM member_rows mr
  WHERE mr.status = 'Active'
    AND mr.payment IN ('Paid', 'Part Paid')
    AND COALESCE(NULLIF(trim(mr.category), ''), '') <> 'Pavilion Key'
), eligible_memberships AS (
  SELECT
    mr.raw_member_id,
    mr.membership,
    mr.category,
    mr.season,
    mr.status,
    mr.payment,
    mr.venue_id,
    mr.british_tennis_number,
    mr.email_address,
    EXISTS (
      SELECT 1 FROM signup_rows sr
      WHERE sr.product = mr.membership
    ) AS has_signup
  FROM member_rows mr
  JOIN latest_eligible_season les
    ON mr.season = les.latest_season
  WHERE mr.status = 'Active'
    AND mr.payment IN ('Paid', 'Part Paid')
    AND COALESCE(NULLIF(trim(mr.category), ''), '') <> 'Pavilion Key'
  ORDER BY mr.display_order, mr.membership, mr.raw_member_id
)
SELECT
  COALESCE((SELECT member_name FROM base_member), ${memberSql})::text AS member,
  (SELECT raw_member_id FROM base_member) AS raw_member_id,
  COALESCE((SELECT json_agg(to_jsonb(mr)) FROM member_rows mr), '[]'::json) AS member_rows,
  COALESCE((SELECT json_agg(to_jsonb(em)) FROM eligible_memberships em), '[]'::json) AS eligible_memberships,
  COALESCE((SELECT json_agg(to_jsonb(sr)) FROM signup_rows sr), '[]'::json) AS signup_rows,
  COALESCE((SELECT best_contact FROM best_contact), '{}'::jsonb) AS best_contact;
`;
return [{ json: { member, query: { member, membership, email }, raw_member_id: memberId === 'NULL' ? null : Number.parseInt(memberId, 10), n8n_base_url: n8nBaseUrl, sql } }];

const source = $('Build Confirm Query').first()?.json ?? {};
const row = $input.first()?.json ?? {};
const sourceQuery = source.query ?? {};
const parseMaybe = (value, fallback) => {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'string') {
    try { return JSON.parse(value); } catch { return fallback; }
  }
  return value;
};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const member = clean(row.member);
const rawMemberId = clean(row.raw_member_id);
const selectedMembership = clean(sourceQuery.membership);
const selectedEmail = clean(sourceQuery.email ?? sourceQuery.email_address);
const memberRows = parseMaybe(row.member_rows, []);
const eligibleMemberships = parseMaybe(row.eligible_memberships, []);
const bestContact = parseMaybe(row.best_contact, {}) || {};
const pick = (...values) => values.map(clean).find(Boolean) ?? '';
const summaryAddress = [bestContact.address_1, bestContact.address_2, bestContact.address_3, bestContact.town, bestContact.county, bestContact.postcode].map(clean).filter(Boolean);
const summaryEmail = pick(selectedEmail, bestContact.email_address, ...memberRows.map((item) => item.email_address));
const bestVenueId = pick(bestContact.venue_id, ...eligibleMemberships.map((item) => item.venue_id), ...memberRows.map((item) => item.venue_id));
const bestBtn = pick(...eligibleMemberships.map((item) => item.british_tennis_number), ...memberRows.map((item) => item.british_tennis_number));
const n8nBaseUrl = clean(source.n8n_base_url) || 'http://n8n:5678';
const uncapturedOptions = eligibleMemberships.filter((item) => !item.has_signup);
const preselectedMembership = (() => {
  if (selectedMembership && uncapturedOptions.some((item) => clean(item.membership) === selectedMembership)) return selectedMembership;
  if (uncapturedOptions.length === 1) return clean(uncapturedOptions[0].membership);
  if (uncapturedOptions.length > 0) return clean(uncapturedOptions[0].membership);
  return '';
})();
const renderOption = (item) => {
  const membership = clean(item.membership);
  const checked = membership === preselectedMembership ? ' checked' : '';
  const disabled = item.has_signup ? ' disabled' : '';
  const statusText = item.has_signup ? 'Signup already captured' : 'Available for backfill';
  return `<label class="option${item.has_signup ? ' option-disabled' : ''}"><input type="radio" name="product" value="${escapeHtml(membership)}"${checked}${disabled}><span class="option-body"><strong>${escapeHtml(membership)}</strong><small>Season ${escapeHtml(item.season)} | ${escapeHtml(item.payment)} | ${escapeHtml(statusText)}</small></span></label>`;
};
const optionsHtml = eligibleMemberships.length
  ? eligibleMemberships.map(renderOption).join('')
  : '<div class="empty-state">No eligible current paid memberships were found for backfill.</div>';
const canSubmit = uncapturedOptions.length > 0;
const actionButtons = canSubmit
  ? `<button class="button" type="submit" name="add_to_batch" value="false">Create Signup Only</button><button class="button button-secondary" type="submit" name="add_to_batch" value="true">Create Signup + Add to Current Batch</button>`
  : '<span class="pill success">Nothing to create. All eligible memberships already have signup capture.</span>';
const guidance = eligibleMemberships.length > 1
  ? 'Multiple current memberships were found. Select the correct category before creating the backfill.'
  : 'Review the details below, then confirm the backfill.';
const batchingNote = canSubmit
  ? '<p class="meta note">Use <strong>Create Signup Only</strong> if the member was already handled manually in a previous batch. Use the second button only when you want the new backfill added to the current processing batch.</p>'
  : '';
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${escapeHtml(member || 'Confirm backfill')}</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f7f8fc;
      --panel: #ffffff;
      --ink: #2e3d4e;
      --muted: #6b7785;
      --line: #e2e8f0;
      --accent: #509ee3;
      --accent-dark: #2f80d8;
      --soft: #f2f7fd;
      --button-soft: #eef2f7;
      --success-bg: #edf8f2;
      --success-ink: #1f7a4d;
      --warning-bg: #fff6e6;
      --warning-ink: #9a6700;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      font-family: Lato, 'Helvetica Neue', Arial, sans-serif;
      color: var(--ink);
      background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%);
      padding: 24px;
    }
    .wrap { max-width: 960px; margin: 0 auto; display: grid; gap: 20px; }
    .hero, .panel { background: var(--panel); border: 1px solid var(--line); border-radius: 18px; box-shadow: 0 18px 40px rgba(53, 72, 91, 0.08); }
    .hero, .panel { padding: 24px; }
    h1 { margin: 0 0 6px; font-size: 32px; line-height: 1.05; letter-spacing: -0.02em; }
    .lede, .meta { margin: 0; color: var(--muted); font-size: 16px; }
    .note { margin-top: 14px; }
    .summary { display: grid; gap: 14px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); margin-top: 20px; }
    .summary-card { border: 1px solid var(--line); border-radius: 14px; padding: 16px; background: var(--soft); }
    .summary-card h2 { margin: 0 0 8px; font-size: 14px; text-transform: uppercase; letter-spacing: 0.08em; color: var(--muted); }
    .summary-card p { margin: 0; font-size: 18px; line-height: 1.4; }
    .option-list { display: grid; gap: 12px; margin-top: 18px; }
    .option { display: flex; gap: 12px; align-items: flex-start; border: 1px solid var(--line); border-radius: 14px; padding: 14px 16px; background: #fff; }
    .option input { margin-top: 5px; }
    .option-body { display: grid; gap: 4px; }
    .option-body small { color: var(--muted); }
    .option-disabled { background: #fafbfc; color: var(--muted); }
    .actions { margin-top: 20px; display: flex; gap: 12px; flex-wrap: wrap; align-items: center; }
    .button, .close-button { display: inline-flex; align-items: center; justify-content: center; padding: 12px 18px; border-radius: 999px; text-decoration: none; font-weight: 700; border: 0; cursor: pointer; font: inherit; }
    .button { background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dark) 100%); color: #fff; box-shadow: 0 10px 24px rgba(80, 158, 227, 0.22); }
    .button-secondary { background: var(--button-soft); color: var(--ink); border: 1px solid var(--line); box-shadow: none; }
    .close-button { background: var(--button-soft); color: var(--ink); border: 1px solid var(--line); }
    .pill { display: inline-flex; align-items: center; padding: 10px 14px; border-radius: 999px; font-weight: 700; background: var(--success-bg); color: var(--success-ink); }
    .empty-state { padding: 16px; border-radius: 14px; background: var(--warning-bg); color: var(--warning-ink); border: 1px solid #f2d08a; }
    @media (max-width: 720px) { body { padding: 14px; } .hero, .panel { padding: 18px; } h1 { font-size: 28px; } }
  </style>
</head>
<body>
  <div class="wrap">
    <section class="hero">
      <h1>${escapeHtml(member || 'Confirm backfill')}</h1>
      <p class="lede">${escapeHtml(guidance)}</p>
      <div class="summary">
        <div class="summary-card"><h2>Email</h2><p>${escapeHtml(summaryEmail || 'Not available')}</p></div>
        <div class="summary-card"><h2>Identifiers</h2><p>Row ID: ${escapeHtml(rawMemberId || 'Not available')}<br>Venue ID: ${escapeHtml(bestVenueId || 'Not available')}<br>Tennis Number: ${escapeHtml(bestBtn || 'Not available')}</p></div>
        <div class="summary-card" style="grid-column: 1 / -1;"><h2>Best Address</h2><p>${summaryAddress.length ? summaryAddress.map(escapeHtml).join('<br>') : 'Not available'}</p></div>
      </div>
    </section>
    <section class="panel">
      <h2>Eligible Memberships</h2>
      <p class="meta">Only current, active, paid memberships from the latest season are offered here. Pavilion Key is excluded.</p>
      ${batchingNote}
      <form method="get" action="${n8nBaseUrl}/webhook/create-missing-signup-capture">
        <input type="hidden" name="member" value="${escapeHtml(member)}">
        <input type="hidden" name="venue_id" value="${escapeHtml(bestVenueId)}">
        <input type="hidden" name="btn" value="${escapeHtml(bestBtn)}">
        <input type="hidden" name="request_source" value="confirm_missing_signup_capture">
        <div class="option-list">${optionsHtml}</div>
        <div class="actions">
          ${actionButtons}
          <button type="button" class="close-button" onclick="window.close()">Close</button>
        </div>
      </form>
    </section>
  </div>
</body>
</html>`;
return [{ json: { html } }];
